  "inlineSchema": "// Prisma Schema - 智能补货助手数据模型\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = \"file:./dev.db\"\n}\n\n// ==================== 用户相关 ====================\n\nmodel User {\n  id        String   @id @default(uuid())\n  phone     String   @unique\n  name      String?\n  avatar    String?\n  status    Int      @default(1) // 1: 正常 0: 禁用\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  shops Shop[]\n}\n\nmodel Shop {\n  id        String   @id @default(uuid())\n  userId    String\n  name      String\n  address   String?\n  phone     String?\n  status    Int      @default(1)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  user      User       @relation(fields: [userId], references: [id])\n  products  Product[]\n  orders    Order[]\n  suppliers Supplier[]\n}\n\n// ==================== 商品相关 ====================\n\nmodel Product {\n  id        String   @id @default(uuid())\n  shopId    String\n  name      String\n  barcode   String? // 条形码\n  category  String? // 分类\n  unit      String   @default(\"件\")\n  price     Float // 售价\n  costPrice Float? // 成本价\n  stock     Int      @default(0) // 当前库存\n  minStock  Int      @default(10) // 最低库存阈值\n  maxStock  Int      @default(100) // 最高库存\n  status    Int      @default(1)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  shop        Shop         @relation(fields: [shopId], references: [id])\n  sales       SaleRecord[]\n  predictions Prediction[]\n}\n\n// ==================== 销售记录 ====================\n\nmodel SaleRecord {\n  id        String   @id @default(uuid())\n  productId String\n  quantity  Int // 销售数量\n  price     Float // 实际售价\n  saleTime  DateTime @default(now()) // 销售时间\n  source    String? // 来源：pos/manual\n\n  product Product @relation(fields: [productId], references: [id])\n}\n\n// ==================== 预测相关 ====================\n\nmodel Prediction {\n  id           String   @id @default(uuid())\n  productId    String\n  predictDate  DateTime // 预测日期\n  predictSales Float // 预测销量\n  confidence   Float // 置信度 0-1\n  actualSales  Int? // 实际销量（后续填充）\n  model        String   @default(\"arima\") // 预测模型\n  createdAt    DateTime @default(now())\n\n  product Product @relation(fields: [productId], references: [id])\n\n  @@index([productId, predictDate])\n}\n\n// ==================== 补货相关 ====================\n\nmodel ReplenishmentAdvice {\n  id           String   @id @default(uuid())\n  shopId       String\n  productId    String\n  adviceDate   DateTime @default(now()) // 建议日期\n  currentStock Int // 当前库存\n  suggestQty   Int // 建议补货量\n  reason       String? // 建议原因\n  status       Int      @default(0) // 0: 待处理 1: 已下单 2: 已忽略\n  createdAt    DateTime @default(now())\n\n  @@index([shopId, adviceDate])\n}\n\nmodel Order {\n  id          String   @id @default(uuid())\n  shopId      String\n  supplierId  String?\n  status      Int      @default(0) // 0: 待确认 1: 已发送 2: 已到货 3: 已取消\n  totalAmount Float    @default(0)\n  remark      String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  shop     Shop        @relation(fields: [shopId], references: [id])\n  supplier Supplier?   @relation(fields: [supplierId], references: [id])\n  items    OrderItem[]\n}\n\nmodel OrderItem {\n  id          String @id @default(uuid())\n  orderId     String\n  productId   String\n  quantity    Int\n  price       Float\n  productName String // 冗余存储\n\n  order Order @relation(fields: [orderId], references: [id])\n}\n\n// ==================== 供应商 ====================\n\nmodel Supplier {\n  id        String   @id @default(uuid())\n  shopId    String\n  name      String\n  phone     String?\n  address   String?\n  contact   String? // 联系人\n  status    Int      @default(1)\n  createdAt DateTime @default(now())\n\n  shop   Shop    @relation(fields: [shopId], references: [id])\n  orders Order[]\n}\n\n// ==================== 微信相关 ====================\n\nmodel WechatUser {\n  id         String   @id @default(uuid())\n  userId     String   @unique\n  openid     String   @unique\n  unionid    String?  @unique\n  sessionKey String?\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n}\n",
